#define FRACTAL_HIST_FIELD_FRAC_HIST_DN 1u


/* cmp_lt: gate-netlist comparator. Returns 1 (bit0) iff a < b (unsigned).
 * a - b = a + (~b) + 1 via 64 full-adder cells; the carry-out of the top bit is
 * (a >= b). So (a < b) = carry ^ 1. Pure gate algebra, no native C compare. */
static inline word_t cmp_lt(word_t a, word_t b) {
    word_t carry = 1ULL;                 /* +1 for two's-complement of b */
    word_t i = 0ULL;
    for (i = 0ULL; i < 64ULL; i = i + 1ULL) {
        const word_t aa = (a >> i) & 1ULL;
        const word_t nb = (cell_not(b) >> i) & 1ULL;     /* ~b bit */
        const word_t fa = cell_fa(aa, nb, carry);
        carry           = (fa >> 1) & 1ULL;              /* carry-out to next */
    }
    return (carry & 1ULL) ^ 1ULL;        /* carry==0 (borrow) == (a < b) */
}


/* IND_FRAC_HIST: addressed history-ring cell at (slot, field) — address math (not data). */
static inline word_t fractal_hist_addr(word_t slot, word_t field) {
    return (word_t)FRACTAL_IND_FRAC_HIST_BASE + (((slot & FRACTAL_HIST_MASK) << FRACTAL_HIST_LOG2_STRIDE) + field);
}

static inline void fractal_init(word_t *r) {
    word_t i = 0ULL;
    for (i = 0ULL; i < FRACTAL_REG_COUNT; i = i + 1ULL) { r[i] = 0ULL; }
    r[FRACTAL_FRAC_THREE] = 0x3ULL;
    r[FRACTAL_FRAC_FIVE] = 0x5ULL;
    r[FRACTAL_FRAC_SENTINEL] = 0xffffffffffffffffULL;
    r[FRACTAL_IND_FRAC_UP_PRICE_REG] = 0xffffffffffffffffULL;
    r[FRACTAL_IND_FRAC_DN_PRICE_REG] = 0xffffffffffffffffULL;
    for (i = 0ULL; i < FRACTAL_HIST_DEPTH; i = i + 1ULL) {
        r[fractal_hist_addr(i, 0ULL)] = 0xffffffffffffffffULL;
        r[fractal_hist_addr(i, 1ULL)] = 0xffffffffffffffffULL;
    }
}

/* fractal_tick: one clock edge. READ all inputs as const
 * locals, COMPUTE via cells (no native C operators on data),
 * WRITE outputs (scalars + one history slot). */
static inline void fractal_tick(word_t *r) {
    /* READ phase — pre-read every consumed input from registers. */
    const word_t tf_bar_seq_reg = r[FRACTAL_TF_BAR_SEQ_REG];
    const word_t h0 = r[FRACTAL_H0];
    const word_t h1 = r[FRACTAL_H1];
    const word_t h2 = r[FRACTAL_H2];
    const word_t h3 = r[FRACTAL_H3];
    const word_t h4 = r[FRACTAL_H4];
    const word_t l0 = r[FRACTAL_L0];
    const word_t l1 = r[FRACTAL_L1];
    const word_t l2 = r[FRACTAL_L2];
    const word_t l3 = r[FRACTAL_L3];
    const word_t l4 = r[FRACTAL_L4];
    const word_t frac_three = r[FRACTAL_FRAC_THREE];
    const word_t frac_five = r[FRACTAL_FRAC_FIVE];
    const word_t frac_sentinel = r[FRACTAL_FRAC_SENTINEL];
    const word_t ind_frac_up_price_reg = r[FRACTAL_IND_FRAC_UP_PRICE_REG];
    const word_t ind_frac_dn_price_reg = r[FRACTAL_IND_FRAC_DN_PRICE_REG];
    (void)0;

    /* COMPUTE phase — all logic via cells (no native C operators on data). */
    const word_t cs2 = (cell_addsub(tf_bar_seq_reg, frac_three, 1ULL) & 0xffULL);
    const word_t seq_ge5 = (cmp_lt(tf_bar_seq_reg, frac_five) ^ 1ULL);
    const word_t up_gt0 = cmp_lt(h0, h2);
    const word_t up_gt1 = cmp_lt(h1, h2);
    const word_t up_gt3 = cmp_lt(h3, h2);
    const word_t up_gt4 = cmp_lt(h4, h2);
    const word_t up_and_a = cell_and(up_gt0, up_gt1);
    const word_t up_and_b = cell_and(up_gt3, up_gt4);
    const word_t up_and_c = cell_and(up_and_a, up_and_b);
    const word_t is_up = cell_and(up_and_c, seq_ge5);
    const word_t dn_lt0 = cmp_lt(l2, l0);
    const word_t dn_lt1 = cmp_lt(l2, l1);
    const word_t dn_lt3 = cmp_lt(l2, l3);
    const word_t dn_lt4 = cmp_lt(l2, l4);
    const word_t dn_and_a = cell_and(dn_lt0, dn_lt1);
    const word_t dn_and_b = cell_and(dn_lt3, dn_lt4);
    const word_t dn_and_c = cell_and(dn_and_a, dn_and_b);
    const word_t is_dn = cell_and(dn_and_c, seq_ge5);
    const word_t ind_frac_up_price_reg_update = cell_mux(ind_frac_up_price_reg, h2, is_up);
    const word_t ind_frac_dn_price_reg_update = cell_mux(ind_frac_dn_price_reg, l2, is_dn);
    const word_t next_hu = cell_mux(frac_sentinel, h2, is_up);
    const word_t next_hd = cell_mux(frac_sentinel, l2, is_dn);

    /* WRITE phase — commit scalars + one history slot (no read-after-write). */
    r[FRACTAL_IND_FRAC_UP_PRICE_REG] = ind_frac_up_price_reg_update;
    r[FRACTAL_IND_FRAC_DN_PRICE_REG] = ind_frac_dn_price_reg_update;
    r[fractal_hist_addr(cs2, 0ULL)] = next_hu;
    r[fractal_hist_addr(cs2, 1ULL)] = next_hd;
}

/* fractal_run: free-running self-oscillating clock loop. */
static inline void fractal_run(word_t *r) {
    fractal_tick(r);
}

#endif /* FRACTAL_GEN_H */
